+  if (taskFn === undefined) return (items) => traverseSerial(items, itemsOrFn as (item: T) => Task<U, E>);
+  return new Task<U[], E>((resolve, reject) => {
+    const values: U[] = [];
+    const iterator = (itemsOrFn as Iterable<T>)[Symbol.iterator]();
