+/** Convert and collect `Maybe`s as a `Result`, using `errValue` for `Nothing`. */
+export function sequenceMaybeAsResult<T extends {}, E>(
+  errValue: E,
+  maybes: Iterable<Maybe<T>>
+): Result<T[], E>;
+export function sequenceMaybeAsResult<T extends {}, E>(errValue: E): (maybes: Iterable<Maybe<T>>) => Result<T[], E>;
+export function sequenceMaybeAsResult<T extends {}, E>(
+  errValue: E,
+  maybes?: Iterable<Maybe<T>>
+): Result<T[], E> | ((maybes: Iterable<Maybe<T>>) => Result<T[], E>) {
+  const op = (items: Iterable<Maybe<T>>): Result<T[], E> => {
+    const values: T[] = [];
+    for (const maybe of items) {
+      if (maybe.isNothing) return Result.err(errValue);
+      values.push(maybe.value);
+    }
+    return Result.ok(values);
+  };
+  return maybes === undefined ? op : op(maybes);
+}
+
+export function traverseMaybeAsResult<T, U extends {}, E>(
+  errValue: E,
+  items: Iterable<T>,
+  fn: (item: T) => Maybe<U>
+): Result<U[], E>;
+export function traverseMaybeAsResult<T, U extends {}, E>(
+  errValue: E
+): (items: Iterable<T>, fn: (item: T) => Maybe<U>) => Result<U[], E>;
+export function traverseMaybeAsResult<T, U extends {}, E>(
+  errValue: E,
+  items?: Iterable<T>,
+  maybeFn?: (item: T) => Maybe<U>
+): Result<U[], E> | ((items: Iterable<T>, fn: (item: T) => Maybe<U>) => Result<U[], E>) {
+  const op = (source: Iterable<T>, fn: (item: T) => Maybe<U>): Result<U[], E> => {
+    const values: U[] = [];
+    for (const item of source) {
+      const maybe = fn(item);
+      if (maybe.isNothing) return Result.err(errValue);
+      values.push(maybe.value);
+    }
+    return Result.ok(values);
+  };
+  return items === undefined || maybeFn === undefined ? op : op(items, maybeFn);
+}
+
+export function zipMaybeAsResult<T extends {}, U extends {}, E>(
+  errValue: E,
+  a: Maybe<T>,
+  b: Maybe<U>
+): Result<[T, U], E>;
+export function zipMaybeAsResult<T extends {}, U extends {}, E>(
+  errValue: E
+): (a: Maybe<T>, b: Maybe<U>) => Result<[T, U], E>;
+export function zipMaybeAsResult<T extends {}, U extends {}, E>(
+  errValue: E,
+  a?: Maybe<T>,
+  b?: Maybe<U>
+): Result<[T, U], E> | ((a: Maybe<T>, b: Maybe<U>) => Result<[T, U], E>) {
+  const op = (first: Maybe<T>, second: Maybe<U>): Result<[T, U], E> => {
+    if (first.isNothing || second.isNothing) return Result.err(errValue);
+    return Result.ok([first.value, second.value]);
+  };
+  return a === undefined || b === undefined ? op : op(a, b);
+}
